import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  date: z.string(),
  time: z.string(),

  user_status: z.object({
    current_project: z.string(),
    funds: z.coerce.number(),
    reputation: z.record(
      z.enum(['domestic', 'overseas']),
      z.object({
        players: z.coerce.number(),
        industry: z.coerce.number(),
        public: z.coerce.number(),
      })
    ),
    platform_relations: z.record(z.string().describe('Tên nền tảng'), z.coerce.number().describe('Giá trị quan hệ')),
    influence: z.record(
      z.enum(['domestic', 'overseas']),
      z.object({
        // Chế độ vận hành hợp nhất
        drivers: z.record(
          z.enum(['data_driven', 'experience_driven']),
          z.object({
            market_favor: z.coerce.number().transform(v => Math.min(Math.max(v, -100), 100)),
            clone_wishes: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)),
          })
        ),
        // Mô hình kinh doanh hợp nhất
        business_models: z.record(
          z.enum(['B2P', 'F2P']),
          z.object({
            market_favor: z.coerce.number().transform(v => Math.min(Math.max(v, -100), 100)),
          })
        ),
      })
    ),
  }),

  products: z
    .record(
      z.string().describe('Tên trò chơi'),
      z.object({
        phase: z.string(),
        design: z.object({
          summary: z.string(),
          worldview: z.string(),
          gameplay: z.string(),
          outline: z.string(),
        }),
        market_data: z.object({
          business_model: z.string(),
          pricing: z.coerce.number(),
          platform_fee: z.coerce.number(),
          is_released_overseas: z.boolean(),
          sales: z.coerce.number(),
          total_revenue: z.coerce.number(),
          player_count: z.coerce.number(),
          iap_revenue: z.coerce.number(),
          arpu: z.coerce.number(),
          other_revenue: z.coerce.number(),
          ccu: z.coerce.number(),
          community_topics: z.record(z.string().describe('topic_name'), z.string().describe('content')),
        }),
      })
    )
    .prefault({}),
});

$(() => {
  registerMvuSchema(Schema);
});
